              if (animClass) {
                if (delay > 0) {
                  setTimeout(function() { el.classList.add(animClass); clearTransformAfterAnim(el); }, delay);
                } else {
                  el.classList.add(animClass);
                  clearTransformAfterAnim(el);
                }
              }
